#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::stream_reader reader(buffer);

    uint32_t packet_id = hexi::read<uint32_t>(reader);

    uint32_t username_len = hexi::read<uint32_t>(reader);
    std::string username = hexi::read_string(reader, username_len);

    uint32_t scores_count = hexi::read<uint32_t>(reader);
    std::vector<uint32_t> scores = hexi::read_container<std::vector<uint32_t>>(reader, scores_count);

    std::string metadata = hexi::read_null_terminated(reader);

    // Skip any remaining padding bytes
    auto remaining = reader.size() - reader.position();
    if (remaining > 0) {
        hexi::skip(reader, remaining);
    }

    return {packet_id, username, scores, metadata};
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::stream_reader reader(buffer);

    uint32_t packet_id = hexi::read<uint32_t>(reader);

    uint32_t username_len = hexi::read<uint32_t>(reader);
    std::string_view username = hexi::read_string(reader, username_len);

    uint32_t scores_count = hexi::read<uint32_t>(reader);
    hexi::skip(reader, scores_count * sizeof(uint32_t)); // Skip scores data

    return {packet_id, username};
}

