DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor<const uint8_t> adaptor(buffer);
    hexi::binary_stream reader(adaptor);

    // Preview data_type without advancing read pointer
    uint8_t data_type;
    reader.peek(&data_type, sizeof(data_type));

    // Check if buffer has at least header size
    uint64_t total_size = adaptor.size();
    uint64_t bytes_needed_header = sizeof(uint8_t) + sizeof(uint32_t);
    if (total_size < bytes_needed_header) {
        return DataResult{0, {}, {}};
    }

    // Read item_count
    uint32_t item_count;
    reader.read(&item_count, sizeof(item_count));

    // Check if remaining bytes are sufficient for items
    uint64_t remaining_bytes = total_size - reader.tell();
    uint64_t item_size = (data_type == 0) ? sizeof(uint32_t) : sizeof(float);
    uint64_t required_bytes = item_count * item_size;

    if (remaining_bytes < required_bytes) {
        return DataResult{0, {}, {}};
    }

    DataResult result;
    if (data_type == 0) {
        result.int_items.resize(item_count);
