#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>

template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    hexi::block_allocator<int, element_count> alloc;
    int allocations = 0;
    int deallocations = 0;

    std::cout << "Block Allocator with " << element_count << " elements" << std::endl;
    std::cout << "Initial free blocks: " << element_count << std::endl;

    // First allocation
    int* ptr1 = alloc.allocate();
    allocations++;
    std::cout << "After 1 allocation: free blocks = " << element_count - (allocations - deallocations) << std::endl;

    // Second allocation
    int* ptr2 = alloc.allocate();
    allocations++;
    std::cout << "After 2 allocations: free blocks = " << element_count - (allocations - deallocations) << std::endl;

    // Deallocate first pointer
    alloc.deallocate(ptr1);
    deallocations++;
    std::cout << "After 1 deallocation: free blocks = " << element_count - (allocations - deallocations) << std::endl;

    // Deallocate second pointer
    alloc.deallocate(ptr2);
    deallocations++;
    std::cout << "After 2 deallocations: free blocks = " << element_count - (allocations - deallocations) << std::endl;

    // Reallocate to reuse freed blocks
    int* ptr3 = alloc.allocate();
    allocations++;
    std::cout << "After 1 reallocation: free blocks = " << element_count - (allocations - deallocations) << std::endl;

    // Cleanup remaining pointer
    alloc.deallocate(ptr3);
    deallocations++;
    std::cout << "After cleanup: free blocks = " << element_count - (allocations - deallocations) << std::endl;
}

